  `field_title` text COMMENT '表的字段的中文名称，存的json',
  `validate` text COMMENT '验证器的配置',
  `validate_code` text COMMENT '验证器的代码',
  `model` text COMMENT '模型的配置',
  `model_code` text COMMENT '模型的代码',
  `service` text COMMENT '服务层 配置',
  `service_code` text COMMENT '服务层 代码',
  `logic` text COMMENT '逻辑层的配置',
  `logic_code` text COMMENT '逻辑层的代码',
  `controller_admin` text COMMENT '后端控制器的配置',
  `controller_admin_code` text COMMENT '后端控制器的代码',
  `controller_api` text COMMENT 'api控制器的配置',
  `controller_api_code` text COMMENT 'api控制器的代码',
  `react_api` text COMMENT '后台api的配置',
  `react_api_code` text COMMENT '后台api的代码',
  `uni_api` text COMMENT '前端api的配置',
  `uni_api_code` text COMMENT '前端api的代码',
  `react_create_update` text COMMENT '添加修改页面的配置',
  `react_create_code` text COMMENT '添加页面的代码',
  `react_update_code` text COMMENT '修改页面的代码',
  `react_form_code` text COMMENT '添加修改页面form的字段代码，是个json，多个form的代码',
  `react_info` text COMMENT 'react 详情页配置',
  `react_info_code` text COMMENT 'react 详情页代码',
  `react_list` text COMMENT 'react列表页面配置',
  `react_list_code` text COMMENT 'react列表页面生成的代码',
  `react_list_component_code` text COMMENT '列表页的其它组件代码，如导入等',
  `react_other` text COMMENT '生成后端其它组件的配置',
  `react_other_code` text COMMENT '生成后端其它组件的代码',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COMMENT='代码生成器的配置';

