-- ----------------------------
-- Table structure for sa_pay_record
-- ----------------------------
DROP TABLE IF EXISTS `sa_pay_record`;
CREATE TABLE `sa_pay_record` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) DEFAULT NULL COMMENT '用户id',
  `type` tinyint(1) DEFAULT NULL COMMENT '类型，1》商城订单支付，2》充值',
  `pay_type` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '支付方式，alipay》支付宝、wechat》微信、money》余额',
  `pay_source` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '支付方式，并没有使用所有：web》网页支付，mp》公众号支付，h5》H5支付，app》APP支付，mini》小程序支付',
  `query_id` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '支付的订单id，如 ,12,13, 会多个订单合并支付',
  `out_trade_no` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '我方支付的订单号',
  `orderno` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '对方支付单号，如支付宝或微信的',
  `total` decimal(10,2) DEFAULT NULL COMMENT '支付总金额',
  `payer_total` decimal(10,2) DEFAULT NULL COMMENT '用户支付总金额，用这个金额来退款',
  `refund_money` decimal(10,2) DEFAULT '0.00' COMMENT '此订单剩余可退金额',
  `success_time` datetime DEFAULT NULL COMMENT '支付的时间',
  `content` text COLLATE utf8mb4_unicode_ci COMMENT '支付回调原始数据',
  PRIMARY KEY (`id`),
  KEY `xfds_user_id` (`user_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='支付记录';

