  `title` varchar(45) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '地区名称',
  `pid` int(11) DEFAULT NULL COMMENT '上级id',
  `sort` int(11) DEFAULT NULL COMMENT '排序',
  `pid_path` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `pid_path_title` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `level` int(11) DEFAULT NULL COMMENT '层级',
  `first` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '首字母',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=3712 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='省市区';

-- ----------------------------
-- Records of sa_region
-- ----------------------------

-- ----------------------------
-- Table structure for sa_token
-- ----------------------------
DROP TABLE IF EXISTS `sa_token`;
CREATE TABLE `sa_token` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `token_key` varchar(100) DEFAULT NULL COMMENT '应用名称',
  `token` varchar(32) DEFAULT NULL COMMENT '存的token',
  PRIMARY KEY (`id`),
  UNIQUE KEY `token_UNIQUE` (`token`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COMMENT='登录用户的token';

