-- ----------------------------
-- Table structure for sa_user
-- ----------------------------
DROP TABLE IF EXISTS `sa_user`;
CREATE TABLE `sa_user` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(50) DEFAULT NULL COMMENT '姓名',
  `tel` varchar(15) DEFAULT NULL COMMENT '手机号',
  `img` varchar(200) DEFAULT NULL COMMENT '头像',
  `status` tinyint(1) DEFAULT '1' COMMENT '状态，1》正常，2》禁用',
  `pid` int(11) DEFAULT NULL COMMENT '上级用户的id',
  `pid_layer` int(11) DEFAULT '0',
  `pid_path` varchar(255) DEFAULT NULL COMMENT '上级路劲，如：,1,2,',
  `create_time` datetime DEFAULT NULL,
  `update_time` datetime DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=29 DEFAULT CHARSET=utf8mb4 COMMENT='用户';

-- ----------------------------
-- Records of sa_user
-- ----------------------------

-- ----------------------------
-- Table structure for sa_user_info
-- ----------------------------
DROP TABLE IF EXISTS `sa_user_info`;
CREATE TABLE `sa_user_info` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL COMMENT '用户id',
  `weixin_mini_openid` varchar(45) DEFAULT NULL COMMENT '微信小程序openid',
  `weixin_mp_openid` varchar(45) DEFAULT NULL COMMENT '微信公众号的openid',
  `weixin_unionid` varchar(45) DEFAULT NULL COMMENT '微信开放平台unionid',
  `message_push` enum('2','1') DEFAULT '1' COMMENT '消息个性化推送开关，1》开，2》关',
  PRIMARY KEY (`id`,`user_id`),
  KEY `sa_user_info_pk1` (`user_id`),
  CONSTRAINT `sa_user_info_pk1` FOREIGN KEY (`user_id`) REFERENCES `sa_user` (`id`) ON DELETE CASCADE ON UPDATE NO ACTION
) ENGINE=InnoDB AUTO_INCREMENT=18 DEFAULT CHARSET=utf8mb4 COMMENT='用户-资料';

-- ----------------------------
-- Records of sa_user_info
-- ----------------------------

-- ----------------------------
-- Table structure for sa_user_total_day
